// --- Validation utilities ---

object DeepLinkValidator {

    private const val ALLOWED_SCHEME = "myapp"

    private val ALLOWED_HOSTS = setOf("profile", "payment")

    // userId must be a positive numeric value, max 19 digits (fits in Long)
    private val USER_ID_PATTERN = Regex("^[1-9][0-9]{0,18}$")

    // transactionId: alphanumeric + hyphens, 1-64 chars (UUID-like)
    private val TRANSACTION_ID_PATTERN = Regex("^[a-zA-Z0-9\\-]{1,64}$")

    // amount: positive decimal, up to 2 decimal places, max 12 digits before decimal
    private val AMOUNT_PATTERN = Regex("^[0-9]{1,12}(\\.[0-9]{1,2})?$")

    private const val MAX_URI_LENGTH = 2048

    fun validateScheme(uri: Uri): Boolean {
        return uri.scheme?.lowercase() == ALLOWED_SCHEME
    }

    fun validateHost(uri: Uri): Boolean {
        return uri.host?.lowercase() in ALLOWED_HOSTS
    }

    fun validateUriLength(uri: Uri): Boolean {
        return uri.toString().length <= MAX_URI_LENGTH
    }

    fun isValidUserId(raw: String?): Boolean {
        return raw != null && USER_ID_PATTERN.matches(raw)
    }

    fun isValidTransactionId(raw: String?): Boolean {
        return raw != null && TRANSACTION_ID_PATTERN.matches(raw)
    }

    fun isValidAmount(raw: String?): Boolean {
        return raw != null && AMOUNT_PATTERN.matches(raw)
    }
}

