object AuthorizationManager {

    /**
     * Returns true if the current user session is authenticated.
     */
    fun isUserAuthenticated(context: Context): Boolean {
        // In production, check your session/token store.
        val prefs = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
        val token = prefs.getString("session_token", null)
        return !token.isNullOrBlank()
    }

    /**
     * Returns the currently authenticated user's ID, or null if not logged in.
     */
    fun getCurrentUserId(context: Context): Long? {
        val prefs = context.getSharedPreferences("auth_prefs", Context.MODE_PRIVATE)
        val id = prefs.getLong("current_user_id", -1L)
        return if (id > 0) id else null
    }
}

// --- Deep Link Parser ---

object DeepLinkParser {

    private const val TAG = "DeepLinkParser"

    /**
     * Parse and validate a deep link URI into a [DeepLinkRoute].
     * Returns [DeepLinkRoute.Unknown] for any invalid or unrecognized URI.
     */
    fun parse(uri: Uri?): DeepLinkRoute {
        if (uri == null) {
            Log.w(TAG, "Null URI received")
            return DeepLinkRoute.Unknown
        }

        // Length check
        if (!DeepLinkValidator.validateUriLength(uri)) {
            Log.w(TAG, "URI exceeds maximum allowed length")
            return DeepLinkRoute.Unknown
        }

        // Scheme check
        if (!DeepLinkValidator.validateScheme(uri)) {
            Log.w(TAG, "Invalid scheme: ${uri.scheme}")
            return DeepLinkRoute.Unknown
        }

        // Host check
        if (!DeepLinkValidator.validateHost(uri)) {
            Log.w(TAG, "Unknown host: ${uri.host}")
            return DeepLinkRoute.Unknown
        }

        return when (uri.host?.lowercase()) {
            "profile" -> parseProfileRoute(uri)
            "payment" -> parsePaymentRoute(uri)
            else -> DeepLinkRoute.Unknown
        }
    }

    /**
     * Expected format: myapp://profile/{userId}
     */
    private fun parseProfileRoute(uri: Uri): DeepLinkRoute {
        val pathSegments = uri.pathSegments
        if (pathSegments.size != 1) {
            Log.w(TAG, "Profile route expects exactly 1 path segment, got ${pathSegments.size}")
            return DeepLinkRoute.Unknown
        }

        val rawUserId = pathSegments[0]
        if (!DeepLinkValidator.isValidUserId(rawUserId)) {
            Log.w(TAG, "Invalid userId format")
            return DeepLinkRoute.Unknown
        }

        val userId = try {
            rawUserId.toLong()
        } catch (e: NumberFormatException) {
            Log.w(TAG, "userId is not a valid Long")
            return DeepLinkRoute.Unknown
        }

        return DeepLinkRoute.Profile(userId)
    }

    /**
     * Expected format: myapp://payment/confirm?transactionId={id}&amount={amount}
     */
    private fun parsePaymentRoute(uri: Uri): DeepLinkRoute {
        val pathSegments = uri.pathSegments
        if (pathSegments.size != 1 || pathSegments[0].lowercase() != "confirm") {
            Log.w(TAG, "Payment route expects path /confirm")
            return DeepLinkRoute.Unknown
        }

        val transactionId = uri.getQueryParameter("transactionId")
        val amount = uri.getQueryParameter("amount")

        if (!DeepLinkValidator.isValidTransactionId(transactionId)) {
            Log.w(TAG, "Invalid transactionId format")
            return DeepLinkRoute.Unknown
        }

        if (!DeepLinkValidator.isValidAmount(amount)) {
            Log.w(TAG, "Invalid amount format")
            return DeepLinkRoute.Unknown
        }

        // Non-null asserted safely because validation passed above
        return DeepLinkRoute.PaymentConfirm(
            transactionId = transactionId!!,
            amount = amount!!
        )
    }
}

// --- Deep Link Router (navigation) ---

object DeepLinkRouter {

    private const val TAG = "DeepLinkRouter"

    /**
     * Navigate to the appropriate Activity based on the parsed route.
     * Performs authorization checks for sensitive routes.
     *
     * @return true if navigation was successful, false otherwise.
     */
    fun route(context: Context, route: DeepLinkRoute): Boolean {
        return when (route) {
            is DeepLinkRoute.Profile -> routeToProfile(context, route)
            is DeepLinkRoute.PaymentConfirm -> routeToPaymentConfirm(context, route)
            is DeepLinkRoute.Unknown -> {
                Log.w(TAG, "Cannot route unknown deep link")
                false
            }
        }
    }

    private fun routeToProfile(context: Context, route: DeepLinkRoute.Profile): Boolean {
        // Profile viewing may be allowed for any authenticated user,
        // but we still require authentication.
        if (!AuthorizationManager.isUserAuthenticated(context)) {
            Log.w(TAG, "Unauthenticated user attempted to access profile via deep link")
            navigateToLogin(context, originalRoute = "profile/${route.userId}")
            return false
        }

        val intent = Intent(context, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, route.userId)
            // Prevent this intent from being used to launch exported activities
            // in other apps or being intercepted.
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
            // Ensure the target is within our own package
            setPackage(context.packageName)
        }

        Log.i(TAG, "Navigating to ProfileActivity for userId=${route.userId}")
        context.startActivity(intent)
        return true
    }

    private fun routeToPaymentConfirm(context: Context, route: DeepLinkRoute.PaymentConfirm): Boolean {
        // Payment confirmation is a sensitive route – require authentication.
        if (!AuthorizationManager.isUserAuthenticated(context)) {
            Log.w(TAG, "Unauthenticated user attempted payment confirm via deep link")
            navigateToLogin(context, originalRoute = "payment/confirm")
            return false
        }

        // Additional authorization: verify the transaction belongs to the current user.
        // In a real app, this would be a server-side check. Here we demonstrate the pattern.
        val currentUserId = AuthorizationManager.getCurrentUserId(context)
        if (currentUserId == null) {
            Log.w(TAG, "Could not determine current user for payment authorization")
            return false
        }

        val intent = Intent(context, PaymentConfirmActivity::class.java).apply {
            putExtra(PaymentConfirmActivity.EXTRA_TRANSACTION_ID, route.transactionId)
            putExtra(PaymentConfirmActivity.EXTRA_AMOUNT, route.amount)
            putExtra(PaymentConfirmActivity.EXTRA_CURRENT_USER_ID, currentUserId)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)
            setPackage(context.packageName)
        }

        Log.i(TAG, "Navigating to PaymentConfirmActivity for transaction=${route.transactionId}")
        context.startActivity(intent)
        return true
    }

    private fun navigateToLogin(context: Context, originalRoute: String) {
        val intent = Intent(context, LoginActivity::class.java).apply {
            putExtra(LoginActivity.EXTRA_REDIRECT_ROUTE, originalRoute)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
            setPackage(context.packageName)
        }
        context.startActivity(intent)
    }
}

